namespace sv_39d8485c2bb84d15890601e77ad28887.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

namespace sv_39d8485c2bb84d15890601e77ad28887.Services;

public class InMemoryTaskService : ITaskService
{
    private readonly List<TaskItem> _tasks = new()
    {
        new(1, "Design wireframes", "Alice", "High", DateTime.Today.AddDays(-2), "To Do"),
        new(2, "Set up CI pipeline", "Bob", "Medium", DateTime.Today.AddDays(3), "In Progress"),
        new(3, "Write unit tests", "Charlie", "Low", DateTime.Today.AddDays(7), "To Do"),
        new(4, "Code review", "Alice", "Medium", DateTime.Today.AddDays(1), "In Progress"),
        new(5, "Deploy to staging", "Bob", "High", DateTime.Today.AddDays(-1), "Done"),
    };

    private int _nextId = 6;

    public Task<List<TaskItem>> GetAllTasksAsync()
        => Task.FromResult(_tasks.ToList());

    public Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate)
    {
        var task = new TaskItem(_nextId++, title, assignee, priority, dueDate, "To Do");
        _tasks.Add(task);
        return Task.FromResult(task);
    }

    public Task UpdateTaskStatusAsync(int taskId, string newStatus)
    {
        var index = _tasks.FindIndex(t => t.Id == taskId);
        if (index >= 0)
        {
            _tasks[index] = _tasks[index] with { Status = newStatus };
        }
        return Task.CompletedTask;
    }
}

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary mt-2">
        <div class="card-body p-2">
            <input class="form-control form-control-sm mb-1" placeholder="Title" @bind="title" />
            <input class="form-control form-control-sm mb-1" placeholder="Assignee" @bind="assignee" />
            <select class="form-select form-select-sm mb-1" @bind="priority">
                <option value="">-- Priority --</option>
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
            <input type="date" class="form-control form-control-sm mb-2" @bind="dueDate" />
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@isSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@isSaving">Cancel</button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee) || string.IsNullOrWhiteSpace(priority))
            return;

        isSaving = true;
        await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        isSaving = false;
        ResetForm();
        IsVisible = false;
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@using sv_39d8485c2bb84d15890601e77ad28887.Services

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <span class="badge bg-primary fs-6">Total: @Tasks.Count</span>
    <span class="badge bg-secondary fs-6">To Do: @Tasks.Count(t => t.Status == "To Do")</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @Tasks.Count(t => t.Status == "In Progress")</span>
    <span class="badge bg-success fs-6">Done: @Tasks.Count(t => t.Status == "Done")</span>
    <span class="badge bg-danger fs-6">Overdue: @Tasks.Count(t => t.DueDate < DateTime.Today)</span>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
}

@using sv_39d8485c2bb84d15890601e77ad28887.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="CanMoveLeft"
                          ShowMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }
            <AddTaskForm OnSave="OnAddTask" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }
}

@page "/board"
@rendermode InteractiveServer
@using sv_39d8485c2bb84d15890601e77ad28887.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var column in columns)
        {
            var index = Array.IndexOf(columns, column);
            var columnTasks = FilteredTasksForColumn(column);
            <BoardColumn ColumnName="@column"
                         Tasks="columnTasks"
                         CanMoveLeft="index > 0"
                         CanMoveRight="index < columns.Length - 1"
                         OnMoveLeft="t => MoveTask(t, columns[index - 1])"
                         OnMoveRight="t => MoveTask(t, columns[index + 1])"
                         OnAddTask="form => AddTask(form, column)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> FilteredTasksForColumn(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) form, string column)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(form.Title, form.Assignee, form.Priority, form.DueDate);
            // CreateTaskAsync defaults to "To Do"; update if adding to a different column
            if (column != "To Do")
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, column);
                newTask = newTask with { Status = column };
            }
            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
    }
}

